package com.google.gson.internal.bind;
import com.google.gson.stream.JsonReader;
import java.lang.reflect.TypeVariable;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonWriter;
import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory.Adapter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Type;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class TypeAdapterRuntimeTypeWrapperTest {

  private Gson mockGson;
  private TypeAdapter<Object> mockDelegate;
  private TypeAdapter<Object> mockRuntimeTypeAdapter;
  private JsonWriter mockJsonWriter;

  @BeforeEach
  void setUp() {
    mockGson = mock(Gson.class);
    mockDelegate = mock(TypeAdapter.class);
    mockRuntimeTypeAdapter = mock(TypeAdapter.class);
    mockJsonWriter = mock(JsonWriter.class);
  }

  @Test
  void write_runtimeTypeSameAsDeclared_usesDelegateWrite() throws IOException {
    String declaredType = String.class.getName();
    Type declared = String.class;
    Object value = "test";

    TypeAdapterRuntimeTypeWrapper<Object> wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegate, declared);

    // Spy getRuntimeTypeIfMoreSpecific to return the same declared type
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(declared).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declared, value);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockDelegate).write(mockJsonWriter, value);
    verifyNoMoreInteractions(mockRuntimeTypeAdapter);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterNotReflective_usesRuntimeTypeAdapter() throws IOException {
    Type declared = Number.class;
    Type runtimeType = Integer.class;
    Object value = 123;

    TypeAdapterRuntimeTypeWrapper<Object> wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegate, declared);

    TypeToken<?> runtimeTypeToken = TypeToken.get(runtimeType);
    when(mockGson.getAdapter(runtimeTypeToken)).thenReturn(mockRuntimeTypeAdapter);
    // Make runtimeTypeAdapter not instance of ReflectiveTypeAdapterFactory.Adapter
    when(mockRuntimeTypeAdapter.getClass()).thenReturn(TypeAdapter.class);

    // Spy getRuntimeTypeIfMoreSpecific to return runtimeType
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declared, value);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockRuntimeTypeAdapter).write(mockJsonWriter, value);
    verify(mockDelegate, never()).write(any(), any());
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateNotReflective_usesDelegate() throws IOException {
    Type declared = Number.class;
    Type runtimeType = Integer.class;
    Object value = 123;

    TypeAdapterRuntimeTypeWrapper<Object> wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegate, declared);

    TypeToken<?> runtimeTypeToken = TypeToken.get(runtimeType);
    when(mockGson.getAdapter(runtimeTypeToken)).thenReturn(mockRuntimeTypeAdapter);

    // Make runtimeTypeAdapter instance of ReflectiveTypeAdapterFactory.Adapter
    Adapter reflectiveAdapter = mock(Adapter.class);
    when(mockRuntimeTypeAdapter).thenReturn(reflectiveAdapter);
    when(mockRuntimeTypeAdapter instanceof Adapter).thenReturn(true);

    // Spy getRuntimeTypeIfMoreSpecific to return runtimeType
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declared, value);

    // Spy isReflective to return false for delegate
    doReturn(false).when(spyWrapper).isReflective(mockDelegate);

    // Use reflection to set mockRuntimeTypeAdapter as instance of Adapter
    setField(wrapper, "delegate", mockDelegate);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockDelegate).write(mockJsonWriter, value);
    verify(mockRuntimeTypeAdapter, never()).write(any(), any());
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateReflective_usesRuntimeTypeAdapter() throws IOException {
    Type declared = Number.class;
    Type runtimeType = Integer.class;
    Object value = 123;

    TypeAdapterRuntimeTypeWrapper<Object> wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegate, declared);

    TypeToken<?> runtimeTypeToken = TypeToken.get(runtimeType);
    when(mockGson.getAdapter(runtimeTypeToken)).thenReturn(mockRuntimeTypeAdapter);

    // Spy getRuntimeTypeIfMoreSpecific to return runtimeType
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declared, value);

    // Spy isReflective to return true for delegate
    doReturn(true).when(spyWrapper).isReflective(mockDelegate);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockRuntimeTypeAdapter).write(mockJsonWriter, value);
    verify(mockDelegate, never()).write(any(), any());
  }

  // Helper method to set private final fields via reflection
  private static void setField(Object target, String fieldName, Object value) {
    try {
      Field field = TypeAdapterRuntimeTypeWrapper.class.getDeclaredField(fieldName);
      field.setAccessible(true);
      field.set(target, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }
}
